var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"제길, 여기 있는 침식체들은 뭔가 달라.","JPN":"くそっ、ここの侵食体は何かが違う。","ENG":"Crap, the C.O.s in this area are somewhat different.","TWN":"可惡，這裡的侵蝕體好像有什麼不一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다른 곳에서 마주쳤으면 쉽게 제압했을 녀석들인데.","JPN":"いつもなら簡単に倒せるのに。","ENG":"They would’ve been easily taken down elsewhere.","TWN":"要是在其他地方遇到，這些傢伙很容易就能解決。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"마왕의 힘이라는 거겠죠. 항상 고준위 침식파가 흐르는 환경이니까요.","JPN":"魔王の力でしょう。常に高レベルの侵食波が流れていますから。","ENG":"It's the power of the Demon Lord. This place is packed with high-level Corruption ray.","TWN":"應該是魔王的力量吧。這個地方一直存在著高侵蝕波。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"넉넉하게 두 급수씩은 높게 쳐 줘도 되겠어요.","JPN":"大目に見積もって、2ランクくらいは強くなっていると見てもいいでしょう。","ENG":"They'll be around two categories higher than usual.","TWN":"足夠它們提升二個等級了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤 너, 혹시 기습할 계획 세우면서 이런 상황은 예상 안 했어?","JPN":"シズカ、奇襲を計画するとき、こういう状況は想定できなかったの？","ENG":"Didn’t you expect something like this to happen when you were planning the attack, Seo Yoon?","TWN":"徐芸！你制定突襲計畫的時候就沒想到過這種情況嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"글쎄. 그런 변수까지 계산할 수 있었으면 점쟁이가 되지 않았을까. 유미나 양.","JPN":"さあ。こんな想定外の事態まで計算できるなら、占い師になってたと思わない、ミナ？","ENG":"If I could, I’d be a fortune teller instead, Mina.","TWN":"這個嘛，要是我連這種變數都能計算出來，那我去當算命師就好啦，劉米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 두 분도 마음을 비우고 현실을 받아들이세요.","JPN":"ハハ、二人とも冷静に現実を受け入れましょう。","ENG":"Ha ha, relax and embrace what's happening around us, you two.","TWN":"哈哈，二位也靜下心接受現實吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"상황을 더 넓게 바라보면 해답을 찾을 수 있지 않을까요?","JPN":"状況をより広く俯瞰できれば、答えが見つかるかもですよ？","ENG":"If we look at things from a bigger perspective, perhaps we could find the answer to this.","TWN":"如果以更開闊的視角去看，應該能找到答案吧？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그래. 우리 아주 제대로 망한 것 같아.","JPN":"そうね。完全に詰んだみたい。","ENG":"Yup. We're totally doomed.","TWN":"是啊，我們好像徹底完蛋了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하아…… 하……. 하…….","JPN":"はあ……はぁ……はぁ……","ENG":"*Huff...* *Huff...* *Huff...*","TWN":"哈啊……哈……哈……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아, 그만둬!","JPN":"ルクレシア、やめるんだ！","ENG":"Stop it, Lucrecia!","TWN":"露可蕾西亞，住手！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미스틸테인에 입은 상처는 쉽게 회복되지 않아. 그렇게 쇠약해진 상태로 무리했다간…….","JPN":"ミスティルテインによって負った傷は簡単には回復しない。そんなに弱くなった体で無理したら……","ENG":"Wounds from Misteltein don't heal easily. You’re already in bad shape. If you keep fighting like that...","TWN":"米斯特丁造成的傷口很難恢復，以這樣衰弱的狀態硬撐下去……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저는……. 괜찮습니다. 이 정도 부상은 얼마든지 버틸 수 있어요.","JPN":"私は……大丈夫です。この程度の負傷はいくらでも耐えられます。","ENG":"I'm... okay. This is nothing.","TWN":"我……沒關係。這種程度的傷我還撐得住。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아직 늑대에게 미련이 남으셨다면, 제가 대신 손을 더럽혀도 될 일이지요.","JPN":"まだ狼に未練がおありなら、私が代わりに手を下しましょう。","ENG":"If you're still having second thoughts about the Wolf, I will do the dirty work for you.","TWN":"如果您對狼還有留戀，那我可以替您動手。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그런 게 아니야! 나는 더 이상, 구원에는……!","JPN":"そうじゃない！　僕はもう、救いには……！","ENG":"That's not it! I don't want Salvation–!","TWN":"不是那樣的！我再也不想要，救贖……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"맹세를 잊지 마세요, 구원자님.","JPN":"誓いを忘れないでください。救世主様。","ENG":"Do not forget your oath, Savior.","TWN":"請別忘了誓言，救贖者大人。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};